cat > /usr/ikuai/script/ipgroup.sh <<'WG_WAN_PATCH__usr_ikuai_script_ipgroup_sh'
#!/bin/bash /etc/ikcommon
Include ipset.sh, ipmacgroup.sh

boot()
{
	init
}

init()
{
	ipgroup_get_name_to_cache
	addrgroup_get_name_to_cache
	sql_config_get_list $IK_DB_CONFIG "select * from ipgroup" |\
	while read config ;do
		if [ -n "$config" ];then
			local $config
			if [ "$type" = "1" ]; then
				__addrpool_rule_add
			fi
			__exec_rule_batch_add
		fi
	done
	china_iplib_refresh_ipset >/dev/null 2>&1 || true
}

add() {
	__check_param || exit 1
	__check_addr_pool_is_valid || exit 1
	__check_group_name || exit 1
	local sql_param="comment:str group_name:str addr_pool:str type:int"
	if SqlMsg=$(sql_config_insert $IK_DB_CONFIG ipgroup $sql_param) ;then
		local id=$SqlMsg

		if [ "$type" = "1" ]; then
			__addrpool_rule_add >/dev/null 2>&1
			addrgroup_get_name_to_cache
		fi
		__exec_rule_batch_add >/dev/null 2>&1 &
		ipgroup_get_name_to_cache
		echo "$id"
		return 0
	else
		echo "$SqlMsg"
		return 1
	fi
}

del()
{
	sql_config_get_list $IK_DB_CONFIG "select type,group_name from ipgroup where id in ($id);delete from ipgroup where id in ($id);" |\
	while read config ;do
		if [ -n "$config" ];then
			local $config
		
			__exec_rule_del >/dev/null 2>&1 &
			if [ "$type" = "1" ]; then
				__addrpool_rule_del >/dev/null 2>&1
			fi
		fi
	done
	ipgroup_get_name_to_cache
	addrgroup_get_name_to_cache
}

edit()
{
	__check_param || exit 1
	__check_addr_pool_is_valid || exit 1
	__check_group_name || exit 1
	local sql_param="comment:str group_name:str addr_pool:str type:int"
	local res=$(sql_config_get_list $IK_DB_CONFIG "select * from ipgroup where id=$id" prefix=old_)
	if [ "res" = "" ];then
		return 0
	fi
	local $res
	if SqlMsg=$(sql_config_update $IK_DB_CONFIG ipgroup "id=$id" $sql_param);then
		if ! NewOldVarl group_name type ;then
			if [ "$old_type" = "1" ]; then
				group_name=$old_group_name __addrpool_rule_del 2>/dev/null
			fi
			group_name=$old_group_name __exec_rule_del 2>/dev/null
		fi
		if [ "$type" = "1" ]; then
			__addrpool_rule_add >/dev/null 2>&1
		fi
		__exec_rule_batch_add >/dev/null 2>&1 &
		ipgroup_get_name_to_cache
		addrgroup_get_name_to_cache
		return 0
	else
		echo "$SqlMsg"
		return 1
	fi
}

vrrp_init()
{
	__clean
	sqlite3 $IK_DB_CONFIG "delete from ipgroup"	
	sqlite3 $IK_DIR_LOG/vrrp/conf/config.db ".dump ipgroup" |grep "^INSERT"| sqlite3 $IK_DB_CONFIG
	init
}

show()
{
	local __filter=$(sql_auto_get_filter)
	local __order=$(sql_auto_get_order)
	local __limit=$(sql_auto_get_limit)
	local __where="$__filter $__order $__limit"
	Show __json_result__
}

__show_total()
{
	local total=$(sqlite3 $IK_DB_CONFIG "select count() from ipgroup $__filter")
	json_append __json_result__ total:int
}

__show_data()
{
	local sql_show="select * from ipgroup $__where"
	local data=$(sql_config_get_json $IK_DB_CONFIG "$sql_show")
	json_append __json_result__ data:json
	return 0;
}


__china_iplib_conf()
{
	echo /etc/mnt/ikuai/china_iplib.conf
}

__china_iplib_defaults()
{
	local conf=$(__china_iplib_conf)
	[ -f "$conf" ] && return
	mkdir -p /etc/mnt/ikuai/china_iplib 2>/dev/null
	cat > "$conf" <<EOF
ENABLE='0'
GROUP_NAME='china_auto'
CHINA_URL='https://ispip.clang.cn/all_cn.txt'
EOF
}

__china_quote()
{
	echo "$1" | sed "s/'/'\\''/g"
}

__show_china_iplib()
{
	__china_iplib_defaults
	local conf=$(__china_iplib_conf)
	local ENABLE=0 GROUP_NAME=china_auto CHINA_URL=https://ispip.clang.cn/all_cn.txt
	. "$conf" 2>/dev/null
	local last_update=""
	local count="0"
	[ -f /etc/mnt/ikuai/china_iplib/last_update.log ] && last_update=$(cat /etc/mnt/ikuai/china_iplib/last_update.log)
	if [ -s /etc/mnt/ikuai/china_iplib/count ]; then
		count=$(cat /etc/mnt/ikuai/china_iplib/count 2>/dev/null)
	elif [ -s /etc/mnt/ikuai/china_iplib/china_ipv4.txt ]; then
		count=$(grep -Ec '^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+/[0-9]+$' /etc/mnt/ikuai/china_iplib/china_ipv4.txt 2>/dev/null)
	else
		count=$(echo "$last_update" | sed -n 's/.* updated .* \([0-9][0-9]*\) routes.*/\1/p' | tail -1)
		[ "$count" ] || count=$(sqlite3 $IK_DB_CONFIG "select addr_pool from ipgroup where group_name='$GROUP_NAME'" 2>/dev/null | awk -F, '{if($0=="")print 0;else print NF}' | tail -1)
	fi
	local china_iplib=$(printf '{"enable":"%s","group_name":"%s","china_url":"%s","last_update":"%s","count":"%s"}' "$ENABLE" "$GROUP_NAME" "$CHINA_URL" "$last_update" "${count:-0}")
	json_append __json_result__ china_iplib:json
}

china_iplib_save()
{
	mkdir -p /etc/mnt/ikuai/china_iplib 2>/dev/null
	local conf=$(__china_iplib_conf)
	local enable="${enable:-0}"
	[ "$enable" = "1" ] || enable=0
	cat > "$conf" <<EOF
ENABLE='$( __china_quote "$enable" )'
GROUP_NAME='$( __china_quote "${group_name:-china_auto}" )'
CHINA_URL='$( __china_quote "${china_url:-https://ispip.clang.cn/all_cn.txt}" )'
EOF
	return 0
}

__show_china_iplib_save()
{
	china_iplib_save >/dev/null 2>&1
}

__china_fetch_file()
{
	local url="$1" out="$2"
	if command -v curl >/dev/null 2>&1; then
		curl -L --connect-timeout 15 --max-time 90 -o "$out" "$url" >/dev/null 2>&1
		return $?
	fi
	if command -v wget >/dev/null 2>&1; then
		wget -T 90 -O "$out" "$url" >/dev/null 2>&1
		return $?
	fi
	return 1
}

china_iplib_group_base()
{
	local group="${1:-china_auto}"
	group=$(echo "$group" | sed 's/[^A-Za-z0-9_]/_/g' | cut -c1-21)
	[ "$group" ] || group=china_auto
	echo "$group"
}

china_iplib_load_ipset()
{
	local src="$1"
	local group="$(china_iplib_group_base "$2")"
	local cachefile=/tmp/iktmp/.china_iplib_${group}.$$

	[ -s "$src" ] || return 1
	mkdir -p /tmp/iktmp 2>/dev/null
	ipset -N group_$group hash:net maxelem 262144 2>/dev/null || ipset -N group_$group hash:net 2>/dev/null || true
	ipset -F group_$group 2>/dev/null || true
	> "$cachefile"
	while read ip; do
		[ "$ip" ] || continue
		echo "-! add group_$group $ip" >> "$cachefile"
	done < "$src"
	ipset_restore "$cachefile"
	rm -f "$cachefile"
}

china_iplib_refresh_ipset()
{
	__china_iplib_defaults
	local conf=$(__china_iplib_conf)
	local ENABLE=0 GROUP_NAME=china_auto CHINA_URL=https://ispip.clang.cn/all_cn.txt
	. "$conf" 2>/dev/null
	GROUP_NAME=$(china_iplib_group_base "$GROUP_NAME")
	[ -s /etc/mnt/ikuai/china_iplib/china_ipv4.txt ] || return 1
	sqlite3 $IK_DB_CONFIG "select id from ipgroup where group_name='$GROUP_NAME' limit 1" 2>/dev/null | grep -q . || return 1
	china_iplib_load_ipset /etc/mnt/ikuai/china_iplib/china_ipv4.txt "$GROUP_NAME"
}

china_iplib_cleanup_groups()
{
	local group="$(china_iplib_group_base "$1")"
	group_name="$group" __exec_rule_del >/dev/null 2>&1 || true
	for oldg in $(sqlite3 $IK_DB_CONFIG "select group_name from ipgroup where group_name like '${group}_%'" 2>/dev/null); do
		group_name="$oldg" __exec_rule_del >/dev/null 2>&1 || true
	done
	sqlite3 $IK_DB_CONFIG "delete from ipgroup where group_name='$group' or group_name like '${group}_%'" >/dev/null 2>&1
	ipgroup_get_name_to_cache
	return 0
}

__show_china_iplib_cleanup()
{
	__china_iplib_defaults
	local conf=$(__china_iplib_conf)
	local ENABLE=0 GROUP_NAME=china_auto CHINA_URL=https://ispip.clang.cn/all_cn.txt
	. "$conf" 2>/dev/null
	china_iplib_cleanup_groups "$GROUP_NAME" >/dev/null 2>&1
}

china_iplib_rebuild_groups()
{
	local src="$1"
	local group="$(china_iplib_group_base "$2")"
	local dir=/etc/mnt/ikuai/china_iplib
	local tmp=/tmp/iktmp/china_iplib_rebuild.$$

	mkdir -p "$dir" /tmp/iktmp 2>/dev/null
	[ -s "$src" ] || { echo "empty ip list"; return 1; }

	grep -E '^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+/[0-9]+$' "$src" | sort -u > "$tmp.clean"
	[ -s "$tmp.clean" ] || { rm -f "$tmp.clean"; echo "empty ip list"; return 1; }

	local count=$(wc -l < "$tmp.clean")
	cp "$tmp.clean" "$dir/china_ipv4.txt" 2>/dev/null || { rm -f "$tmp.clean"; return 1; }

	china_iplib_cleanup_groups "$group" >/dev/null 2>&1 || true

	group_name="$group"
	addr_pool="0.0.0.0/32"
	comment="China IP auto $(date '+%F %T') $count routes; stored in ipset"
	type=0
	sqlite3 $IK_DB_CONFIG "insert into ipgroup (group_name,addr_pool,comment,type) values ('$( __china_quote "$group_name" )','$( __china_quote "$addr_pool" )','$( __china_quote "$comment" )',0)" >/dev/null 2>&1 || {
		rm -f "$tmp".*
		echo "insert ipgroup failed"
		return 1
	}
	china_iplib_load_ipset "$dir/china_ipv4.txt" "$group" >/dev/null 2>&1 || {
		rm -f "$tmp".*
		echo "load ipset failed"
		return 1
	}

	echo "$count" > "$dir/count"
	echo "$(date '+%F %T') updated $group $count routes, single logical group" > "$dir/last_update.log"
	ipgroup_get_name_to_cache
	rm -f "$tmp".*
	return 0
}

__show_china_iplib_rebuild()
{
	__china_iplib_defaults
	local conf=$(__china_iplib_conf)
	local ENABLE=0 GROUP_NAME=china_auto CHINA_URL=https://ispip.clang.cn/all_cn.txt
	. "$conf" 2>/dev/null
	china_iplib_rebuild_groups /etc/mnt/ikuai/china_iplib/china_ipv4.txt "$GROUP_NAME" >/dev/null 2>&1
}

china_iplib_update()
{
	__china_iplib_defaults
	local conf=$(__china_iplib_conf)
	local ENABLE=0 GROUP_NAME=china_auto CHINA_URL=https://ispip.clang.cn/all_cn.txt
	. "$conf" 2>/dev/null
	local dir=/etc/mnt/ikuai/china_iplib
	local tmp=/tmp/iktmp/china_iplib.$$ 
	mkdir -p "$dir" /tmp/iktmp 2>/dev/null
	__china_fetch_file "$CHINA_URL" "$tmp.raw" || { echo "download failed"; rm -f "$tmp.raw"; return 1; }
	grep -E '^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+/[0-9]+$' "$tmp.raw" | sort -u > "$tmp.clean"
	[ -s "$tmp.clean" ] || { echo "empty ip list"; rm -f "$tmp.raw" "$tmp.clean"; return 1; }
	china_iplib_rebuild_groups "$tmp.clean" "$GROUP_NAME" || { rm -f "$tmp.raw" "$tmp.clean"; return 1; }
	rm -f "$tmp.raw" "$tmp.clean"
	return 0
}

__show_china_iplib_update()
{
	china_iplib_update >/dev/null 2>&1
}

EXPORT()
{
	Include import_export.sh
	local format=${format:-txt}
	if errmsg=$(export_txt $IK_DB_CONFIG ipgroup $format $IK_DIR_EXPORT/ipgroup.$format) ;then
		echo "ipgroup.$format"
		return 0
	else
		echo "$errmsg"
		return 1
	fi
}

IMPORT()
{
	Include import_export.sh
	if errmsg=$(import_txt $IK_DB_CONFIG ipgroup $IK_DIR_IMPORT/$filename "$append"  __check_param __clean) ;then
		init >/dev/null 2>/dev/null &
		return 0
	else
		echo "$errmsg"
		return 1
	fi
}


#检查配置的地址池与本地接口网段是否冲突
__check_addr_pool_is_valid()
{
	[ "$type" != "1" ] && return 0

	if ! res=$(check_interface_addrpool "$addr_pool"); then
		Autoiecho param addr_pool_conflict "$res"
		return 1
	fi
	return 0
}

__check_group_name()
{
	if res=$(check_group_name_used ipgroup $group_name 2>/dev/null); then
		Autoiecho ipgroup group_name_inused "$res"	
		return 1
	fi
	return 0
}

__check_param()
{
	check_varl \
		'group_name not macs and not ipall and length >= 1 and length <= 21' \
		'addr_pool ipall' 
}


__clean()
{
	sql_config_get_list $IK_DB_CONFIG "select group_name from ipgroup" |\
	while read config ;do
		if [ -n "$config" ];then
			local $config
			__exec_rule_del
		fi
	done
}

__exec_rule_add()
{
	ipset -N group_$group_name hash:net 2>/dev/null
	ipset -F group_$group_name 2>/dev/null
	ipset_add group_$group_name $addr_pool 2>/dev/null 
}

__exec_rule_del()
{
	ipset -F group_$group_name 2>/dev/null
	ipset -X group_$group_name 2>/dev/null
}

__exec_rule_batch_add()
{
	local cachefile="$IK_DIR_TMP/.ip_${group_name}.$$"

	ipset -N group_$group_name hash:net 2>/dev/null
	ipset -F group_$group_name 2>/dev/null

	> $cachefile
	for ip in ${addr_pool//,/ } ;do
		echo "-! add group_$group_name $ip" >> $cachefile
	done

	ipset_restore "$cachefile"
}

__addrpool_rule_add()
{
	$IK_DIR_SCRIPT/utils/addrpool.lua set "$group_name" "$addr_pool" >/dev/null 2>&1
}

__addrpool_rule_del()
{
	$IK_DIR_SCRIPT/utils/addrpool.lua set "$group_name" "" >/dev/null 2>&1
}
