if [ -f "$DB" ]; then
    sqlite3 "$DB" "alter table wireguard_peers add column out_mode text default 'auto';" >/dev/null 2>&1
    sqlite3 "$DB" "alter table wireguard_peers add column out_wans text default '';" >/dev/null 2>&1
    sqlite3 "$DB" "alter table wireguard_peers add column out_balance text default 'failover';" >/dev/null 2>&1
    sqlite3 "$DB" "alter table wireguard_peers add column peer_privatekey text default '';" >/dev/null 2>&1
    sqlite3 "$DB" "alter table wireguard_peers add column client_dns text default '';" >/dev/null 2>&1
